def generate_invoice_pdf(invoice_data):
    """Generate a PDF invoice from invoice data and return it as a BytesIO buffer."""
    buffer = io.BytesIO()

    doc = SimpleDocTemplate(
        buffer,
        pagesize=letter,
        rightMargin=0.75 * inch,
        leftMargin=0.75 * inch,
        topMargin=0.75 * inch,
        bottomMargin=0.75 * inch
    )

    styles = getSampleStyleSheet()
    elements = []

    # Custom styles
    title_style = ParagraphStyle(
        'InvoiceTitle',
        parent=styles['Title'],
        fontSize=28,
        textColor=colors.HexColor('#2c3e50'),
        spaceAfter=6
    )

    header_style = ParagraphStyle(
        'HeaderStyle',
        parent=styles['Normal'],
        fontSize=11,
        textColor=colors.HexColor('#7f8c8d'),
    )

    label_style = ParagraphStyle(
        'LabelStyle',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#95a5a6'),
    )

    value_style = ParagraphStyle(
        'ValueStyle',
        parent=styles['Normal'],
        fontSize=11,
        textColor=colors.HexColor('#2c3e50'),
    )

    bold_style = ParagraphStyle(
        'BoldStyle',
        parent=styles['Normal'],
        fontSize=11,
        textColor=colors.HexColor('#2c3e50'),
        fontName='Helvetica-Bold'
    )

    notes_style = ParagraphStyle(
        'NotesStyle',
        parent=styles['Normal'],
        fontSize=9,
        textColor=colors.HexColor('#7f8c8d'),
    )

    # Title
    elements.append(Paragraph("INVOICE", title_style))
    elements.append(Spacer(1, 4))

    # Invoice metadata
    meta_data = [
        [
            Paragraph("Invoice Number:", label_style),
            Paragraph(invoice_data["invoice_number"], value_style),
            Paragraph("", label_style),
            Paragraph("Date:", label_style),
            Paragraph(invoice_data["date"], value_style),
        ],
        [
            Paragraph("", label_style),
            Paragraph("", value_style),
            Paragraph("", label_style),
            Paragraph("Due Date:", label_style),
            Paragraph(invoice_data["due_date"], value_style),
        ],
    ]

    meta_table = Table(meta_data, colWidths=[1.2 * inch, 1.5 * inch, 1.5 * inch, 0.9 * inch, 1.5 * inch])
    meta_table.setStyle(TableStyle([
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('TOPPADDING', (0, 0), (-1, -1), 2),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 2),
    ]))
    elements.append(meta_table)
    elements.append(Spacer(1, 20))

    # Horizontal line
    line_data = [["", ""]]
    line_table = Table(line_data, colWidths=[6.5 * inch])
    line_table.setStyle(TableStyle([
        ('LINEBELOW', (0, 0), (-1, 0), 1, colors.HexColor('#ecf0f1')),
    ]))
    elements.append(line_table)
    elements.append(Spacer(1, 15))

    # Bill To section
    bill_to = invoice_data["bill_to"]
    elements.append(Paragraph("BILL TO", ParagraphStyle(
        'BillToLabel',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#3498db'),
        fontName='Helvetica-Bold',
        spaceAfter=6
    )))
    elements.append(Paragraph(bill_to["name"], bold_style))
    elements.append(Paragraph(bill_to["address"], value_style))
    elements.append(Paragraph(f"{bill_to['city']}, {bill_to['state']} {bill_to['zip']}", value_style))
    elements.append(Paragraph(bill_to["email"], value_style))
    elements.append(Spacer(1, 25))

    # Items table
    table_header = [
        Paragraph("Description", ParagraphStyle('TH', parent=styles['Normal'], fontSize=10, textColor=colors.white, fontName='Helvetica-Bold')),
        Paragraph("Qty", ParagraphStyle('TH', parent=styles['Normal'], fontSize=10, textColor=colors.white, fontName='Helvetica-Bold', alignment=1)),
        Paragraph("Unit Price", ParagraphStyle('TH', parent=styles['Normal'], fontSize=10, textColor=colors.white, fontName='Helvetica-Bold', alignment=2)),
        Paragraph("Amount", ParagraphStyle('TH', parent=styles['Normal'], fontSize=10, textColor=colors.white, fontName='Helvetica-Bold', alignment=2)),
    ]

    table_data = [table_header]

    subtotal = 0
    for item in invoice_data["items"]:
        amount = item["quantity"] * item["unit_price"]
        subtotal += amount
        row = [
            Paragraph(item["description"], value_style),
            Paragraph(str(item["quantity"]), ParagraphStyle('Center', parent=value_style, alignment=1)),
            Paragraph(f"${item['unit_price']:,.2f}", ParagraphStyle('Right', parent=value_style, alignment=2)),
            Paragraph(f"${amount:,.2f}", ParagraphStyle('Right', parent=value_style, alignment=2)),
        ]
        table_data.append(row)

    items_table = Table(table_data, colWidths=[3.2 * inch, 0.8 * inch, 1.2 * inch, 1.3 * inch])
    items_table.setStyle(TableStyle([
        # Header row
        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#3498db')),
        ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
        ('TOPPADDING', (0, 0), (-1, 0), 10),
        ('BOTTOMPADDING', (0, 0), (-1, 0), 10),
        ('LEFTPADDING', (0, 0), (-1, -1), 10),
        ('RIGHTPADDING', (0, 0), (-1, -1), 10),
        # Data rows
        ('TOPPADDING', (0, 1), (-1, -1), 8),
        ('BOTTOMPADDING', (0, 1), (-1, -1), 8),
        ('LINEBELOW', (0, 0), (-1, -2), 0.5, colors.HexColor('#ecf0f1')),
        ('LINEBELOW', (0, -1), (-1, -1), 1, colors.HexColor('#bdc3c7')),
        # Alternating row colors
        *[('BACKGROUND', (0, i), (-1, i), colors.HexColor('#f8f9fa')) for i in range(2, len(table_data), 2)],
        ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
    ]))
    elements.append(items_table)
    elements.append(Spacer(1, 15))

    # Totals section
    tax_amount = subtotal * invoice_data["tax_rate"]
    total = subtotal + tax_amount

    totals_right_style = ParagraphStyle('TotalsRight', parent=value_style, alignment=2)
    totals_label_style = ParagraphStyle('TotalsLabel', parent=label_style, alignment=2)
    totals_bold_style = ParagraphStyle('TotalsBold', parent=bold_style, alignment=2, fontSize=13)

    totals_data = [
        [
            "", "",
            Paragraph("Subtotal:", totals_label_style),
            Paragraph(f"${subtotal:,.2f}", totals_right_style)
        ],
        [
            "", "",
            Paragraph(f"Tax ({invoice_data['tax_rate'] * 100:.0f}%):", totals_label_style),
            Paragraph(f"${tax_amount:,.2f}", totals_right_style)
        ],
        [
            "", "",
            Paragraph("TOTAL:", ParagraphStyle('TotalLabel', parent=bold_style, alignment=2, fontSize=13, textColor=colors.HexColor('#3498db'))),
            Paragraph(f"${total:,.2f}", ParagraphStyle('TotalValue', parent=bold_style, alignment=2, fontSize=13, textColor=colors.HexColor('#3498db')))
        ],
    ]

    totals_table = Table(totals_data, colWidths=[3.2 * inch, 0.8 * inch, 1.2 * inch, 1.3 * inch])
    totals_table.setStyle(TableStyle([
        ('TOPPADDING', (0, 0), (-1, -1), 5),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 5),
        ('RIGHTPADDING', (0, 0), (-1, -1), 10),
        ('LEFTPADDING', (0, 0), (-1, -1), 10),
        ('LINEABOVE', (2, 2), (-1, 2), 1.5, colors.HexColor('#3498db')),
    ]))
    elements.append(totals_table)
    elements.append(Spacer(1, 30))

    # Notes
    if invoice_data.get("notes"):
        elements.append(Paragraph("Notes:", ParagraphStyle(
            'NotesLabel',
            parent=styles['Normal'],
            fontSize=10,
            textColor=colors.HexColor('#95a5a6'),
            fontName='Helvetica-Bold',
            spaceAfter=4
        )))
        elements.append(Paragraph(invoice_data["notes"], notes_style))

    doc.build(elements)
    buffer.seek(0)
    return buffer


@app.before_request
def simulate_auth():
    """Simulate authentication middleware - in production this would be real auth middleware."""
    g.user_id = int(request.headers.get('X-User-Id', 1))


@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """Download an invoice PDF by invoice ID."""
    # Validate invoice_id is a positive integer
    if invoice_id <= 0:
        return jsonify({"error": "Invalid invoice ID"}), 400

    # Look up the invoice
    invoice = INVOICES_DB.get(invoice_id)

    if invoice is None:
        return jsonify({"error": "Invoice not found"}), 404

    # Check that the authenticated user owns this invoice
    if invoice["user_id"] != g.user_id:
        return jsonify({"error": "Forbidden: You do not have access to this invoice"}), 403

    # Generate the PDF
    try:
        pdf_buffer = generate_invoice_pdf(invoice)
    except Exception as e:
        return jsonify({"error": "Failed to generate invoice PDF", "details": str(e)}), 500

    filename = f"{invoice['invoice_number']}.pdf"

    return send_file(
        pdf_buffer,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=filename
    )


@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Resource not found"}), 404


@app.errorhandler(500)
def internal_error(error):
    return jsonify({"error": "Internal server error"}), 500


if __name__ == '__main__':
    app.run(debug=True, port=5000)